// Validar configurações do sistema
const dados = $input.item.json;

// Verificar Google Sheets ID
const sheetsIdValido = dados.googleSheetsId && dados.googleSheetsId.length > 40;

// Simular conexão com planilha
const planilhaConectada = true; // Simulação

// Status geral
const sistemaOperacional = sheetsIdValido && planilhaConectada;

// Calcular progresso
const progressoAtual = 85; // 85% completo

const resultado = {
  ...dados,
  sheets_id_valido: sheetsIdValido,
  planilha_conectada: planilhaConectada,
  sistema_operacional: sistemaOperacional,
  progresso_atual: progressoAtual,
  proximos_passos: [
    'Configurar Google Sheets OAuth2',
    'Importar workflows principais',
    'Testar campanhas demo',
    'Ativar WhatsApp Business API'
  ],
  academia: 'Full Force Academia',
  localizacao: 'Matupá-MT',
  email_business: 'contato@primeliontecnologia.com'
};

console.log('🏋️‍♂️ [FULL FORCE ACADEMIA] Sistema validado:', resultado.sistema_operacional);
console.log('📊 [PROGRESSO] Sistema:', resultado.progresso_atual + '%');
console.log('📧 [EMAIL] Configurado:', resultado.email_business);
console.log('📈 [SHEETS] ID:', resultado.googleSheetsId);

return resultado;
